using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var build = BinaryLog.ReadBuild(args[0]);
var errors = build.FindChildrenRecursive<Error>();
var warnings = build.FindChildrenRecursive<Warning>();

Console.WriteLine("=== BUILD ERRORS ===");
Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine();

// Group errors by project
var errorsByProject = new Dictionary<string, List<Error>>();
foreach (var error in errors)
{
    var project = GetProject(error);
    if (!errorsByProject.ContainsKey(project))
        errorsByProject[project] = new List<Error>();
    errorsByProject[project].Add(error);
}

foreach (var kvp in errorsByProject)
{
    Console.WriteLine($"--- Project: {kvp.Key} ---");
    foreach (var e in kvp.Value)
    {
        Console.WriteLine($"  {e.Code}: {e.Text}");
        if (!string.IsNullOrEmpty(e.File))
            Console.WriteLine($"    File: {e.File}({e.LineNumber},{e.ColumnNumber})");
    }
    Console.WriteLine();
}

// Check for project dependency failures
Console.WriteLine("=== PROJECT BUILD RESULTS ===");
var projects = build.FindChildrenRecursive<Project>();
foreach (var p in projects)
{
    if (p.FindChildrenRecursive<Error>().Any())
    {
        Console.WriteLine($"  FAILED: {p.Name} [{p.TargetFramework}]");
    }
}

static string GetProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return p.Name;
        current = current.Parent;
    }
    return "(unknown)";
}
EOF

