foreach (var p in projects)
{
    if (p.Name.EndsWith(".sln") || p.Name.EndsWith(".metaproj")) continue;
    var addItems = p.FindChildrenRecursive<AddItem>();
    foreach (var item in addItems)
    {
        if (item.Name == "ProjectReference")
        {
            foreach (var child in item.Children.OfType<Item>())
            {
                Console.WriteLine($"  {p.Name} -> {child.Text}");
            }
        }
        if (item.Name == "PackageReference")
        {
            foreach (var child in item.Children.OfType<Item>())
            {
                if (child.Text.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase))
                    Console.WriteLine($"  {p.Name} has PackageReference: {child.Text}");
            }
        }
    }
}

// Check if Api.csproj succeeded
Console.WriteLine("\n=== ALL PROJECT OUTCOMES ===");
foreach (var p in projects)
{
    if (p.Name.EndsWith(".metaproj")) continue;
    var hasErrors = p.FindChildrenRecursive<Error>().Any();
    Console.WriteLine($"  {(hasErrors ? "FAIL" : "OK  ")}: {p.Name}");
}

static string GetProject(BaseNode node)
{
    var current = node.Parent;
    while (current != null)
    {
        if (current is Project p) return p.Name;
        current = current.Parent;
    }
    return "(unknown)";
}
